import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { mkdirSync, writeFileSync, readFileSync, rmSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { execFileSync } from 'node:child_process';

import {
  recordAgentStart,
  resolveAgentContext,
  appendLedgerEntry,
  readBranchLedger,
  cleanupStaleLedgers,
  deduplicateAgents,
  filterByThreshold,
} from '../../lib/agent-attribution.js';
import { getCurrentBranch } from '../../lib/git.js';
import { formatAsTrailers, formatAsPrMarkdown } from '../../lib/agent-attribution-format.js';
import type { LedgerEntry } from '../../lib/agent-attribution-types.js';

// ---------------------------------------------------------------------------
// Shared setup: temp project dir with git repo
// ---------------------------------------------------------------------------

let tmpDir: string;
let activityDir: string;

function makeLedgerEntry(overrides: Partial<LedgerEntry> = {}): LedgerEntry {
  return {
    ts: new Date().toISOString(),
    agent: 'test-generator',
    stage: 1,
    duration_ms: 10000,
    success: true,
    summary: 'Generated tests',
    commit_base: 'abc123',
    ...overrides,
  };
}

beforeEach(() => {
  tmpDir = join(tmpdir(), `attr-int-${process.pid}-${Date.now()}`);
  activityDir = join(tmpDir, '.claude', 'agents', 'activity');
  mkdirSync(activityDir, { recursive: true });
  process.env.CLAUDE_PROJECT_DIR = tmpDir;

  // Init git repo so gitExec works
  try {
    execFileSync('git', ['init'], { cwd: tmpDir, stdio: 'pipe' });
    writeFileSync(join(tmpDir, 'README.md'), '# test');
    execFileSync('git', ['add', '.'], { cwd: tmpDir, stdio: 'pipe' });
    execFileSync('git', ['commit', '-m', 'init', '--no-gpg-sign'], { cwd: tmpDir, stdio: 'pipe' });
  } catch { /* git may not be available in CI — tests degrade gracefully */ }
});

afterEach(() => {
  rmSync(tmpDir, { recursive: true, force: true });
  delete process.env.CLAUDE_PROJECT_DIR;
});

// ---------------------------------------------------------------------------
// Tier 3: Session State Pipeline
// ---------------------------------------------------------------------------

describe('Session State Pipeline', () => {
  test('recordAgentStart creates session-state.json', () => {
    recordAgentStart('agent-1');
    const statePath = join(tmpDir, '.claude', 'agents', 'session-state.json');
    expect(existsSync(statePath)).toBe(true);
    const state = JSON.parse(readFileSync(statePath, 'utf8'));
    expect(state.agent_starts['agent-1']).toBeGreaterThan(0);
  });

  test('recordAgentStart records commit_base on first call', () => {
    recordAgentStart('agent-1');
    const statePath = join(tmpDir, '.claude', 'agents', 'session-state.json');
    const state = JSON.parse(readFileSync(statePath, 'utf8'));
    // Should have a commit_base (or empty if git not available)
    expect(typeof state.commit_base).toBe('string');
  });

  test('resolveAgentContext returns start time and increments counter', () => {
    recordAgentStart('agent-1');
    const ctx = resolveAgentContext('agent-1');
    expect(ctx.startMs).toBeGreaterThan(0);
    expect(ctx.counter).toBe(0); // first agent

    recordAgentStart('agent-2');
    const ctx2 = resolveAgentContext('agent-2');
    expect(ctx2.counter).toBe(1); // second agent
  });

  test('resolveAgentContext cleans up start entry', () => {
    recordAgentStart('agent-1');
    resolveAgentContext('agent-1');
    const statePath = join(tmpDir, '.claude', 'agents', 'session-state.json');
    const state = JSON.parse(readFileSync(statePath, 'utf8'));
    expect(state.agent_starts['agent-1']).toBeUndefined();
  });

  test('resolveAgentContext with unknown agent returns 0 startMs', () => {
    const ctx = resolveAgentContext('nonexistent');
    expect(ctx.startMs).toBe(0);
  });

  test('duration calculation: start → stop gives positive duration', () => {
    recordAgentStart('agent-1');
    // Simulate some work time
    const beforeResolve = Date.now();
    const ctx = resolveAgentContext('agent-1');
    const duration = beforeResolve - ctx.startMs;
    // Duration should be non-negative (could be 0 if very fast)
    expect(duration).toBeGreaterThanOrEqual(0);
  });
});

// ---------------------------------------------------------------------------
// Tier 3: Sequential Agent Pipeline
// ---------------------------------------------------------------------------

describe('Sequential Agent Pipeline', () => {
  test('3 sequential agents get stages 0, 1, 2', () => {
    recordAgentStart('a1');
    const ctx1 = resolveAgentContext('a1');
    expect(ctx1.counter).toBe(0); // lead

    recordAgentStart('a2');
    const ctx2 = resolveAgentContext('a2');
    expect(ctx2.counter).toBe(1); // second

    recordAgentStart('a3');
    const ctx3 = resolveAgentContext('a3');
    expect(ctx3.counter).toBe(2); // third
  });

  test('commit_base stays consistent across all agents', () => {
    recordAgentStart('a1');
    const ctx1 = resolveAgentContext('a1');

    recordAgentStart('a2');
    const ctx2 = resolveAgentContext('a2');

    expect(ctx1.commitBase).toBe(ctx2.commitBase);
  });
});

// ---------------------------------------------------------------------------
// Tier 3: Concurrent Access (simulated — same process, interleaved calls)
// ---------------------------------------------------------------------------

describe('Concurrent Access (interleaved)', () => {
  test('multiple recordAgentStart calls preserve all start times', () => {
    recordAgentStart('a1');
    recordAgentStart('a2');
    recordAgentStart('a3');

    const statePath = join(tmpDir, '.claude', 'agents', 'session-state.json');
    const state = JSON.parse(readFileSync(statePath, 'utf8'));
    expect(Object.keys(state.agent_starts)).toHaveLength(3);
    expect(state.agent_starts.a1).toBeGreaterThan(0);
    expect(state.agent_starts.a2).toBeGreaterThan(0);
    expect(state.agent_starts.a3).toBeGreaterThan(0);
  });

  test('interleaved start/stop preserves unresolved agents', () => {
    recordAgentStart('a1');
    recordAgentStart('a2');

    // Resolve a1 but not a2
    resolveAgentContext('a1');

    const statePath = join(tmpDir, '.claude', 'agents', 'session-state.json');
    const state = JSON.parse(readFileSync(statePath, 'utf8'));
    expect(state.agent_starts.a1).toBeUndefined(); // cleaned up
    expect(state.agent_starts.a2).toBeGreaterThan(0); // still there
  });
});

// ---------------------------------------------------------------------------
// Tier 3: Ledger Write + Read Pipeline
// ---------------------------------------------------------------------------

describe('Ledger Write + Read Pipeline', () => {
  test('appendLedgerEntry creates file and readBranchLedger reads it', () => {
    const entry = makeLedgerEntry({ agent: 'security-auditor' });
    // Write to current branch ledger (bufferWrite is sync via global vitest.setup mock)
    appendLedgerEntry(entry);

    // Read back using the temp repo's branch name
    const branch = getCurrentBranch();
    const result = readBranchLedger(branch);
    expect(result.length).toBeGreaterThanOrEqual(1);
    expect(result[0].agent).toBe('security-auditor');
  });

  test('multiple entries append correctly', () => {
    const entries = [
      makeLedgerEntry({ agent: 'agent-1' }),
      makeLedgerEntry({ agent: 'agent-2' }),
      makeLedgerEntry({ agent: 'agent-3' }),
    ];

    entries.forEach(appendLedgerEntry);

    const branch = getCurrentBranch();
    const result = readBranchLedger(branch);
    expect(result.length).toBeGreaterThanOrEqual(3);
  });
});

