describe('Cleanup', () => {
  test('does not clean recent files', () => {
    writeFileSync(join(activityDir, 'recent-branch.jsonl'), '{"agent":"x","ts":"2026-01-01"}\n');
    const cleaned = cleanupStaleLedgers();
    expect(cleaned).toBe(0);
    expect(existsSync(join(activityDir, 'recent-branch.jsonl'))).toBe(true);
  });

  test('returns 0 for empty activity dir', () => {
    rmSync(activityDir, { recursive: true, force: true });
    mkdirSync(activityDir, { recursive: true });
    expect(cleanupStaleLedgers()).toBe(0);
  });

  test('returns 0 when activity dir does not exist', () => {
    rmSync(join(tmpDir, '.claude', 'agents'), { recursive: true, force: true });
    expect(cleanupStaleLedgers()).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// Tier 4: Full E2E Pipeline
// ---------------------------------------------------------------------------

describe('E2E: Full Attribution Pipeline', () => {
  test('complete flow: start → stop → ledger → format → trailers', () => {
    // 1. Simulate SubagentStart
    recordAgentStart('e2e-agent-1');

    // 2. Simulate SubagentStop
    const ctx = resolveAgentContext('e2e-agent-1');
    expect(ctx.counter).toBe(0); // lead
    expect(ctx.startMs).toBeGreaterThan(0);

    const effectiveDuration = Date.now() - ctx.startMs;

    // 3. Create ledger entry (as SubagentStop hook would)
    const entry = makeLedgerEntry({
      agent: 'ork:backend-system-architect',
      stage: ctx.counter === 0 ? 0 : 2,
      duration_ms: effectiveDuration,
      summary: 'Designed API endpoints',
      commit_base: ctx.commitBase,
    });
    appendLedgerEntry(entry);

    // 4. Simulate second agent (parallel)
    recordAgentStart('e2e-agent-2');
    const ctx2 = resolveAgentContext('e2e-agent-2');
    appendLedgerEntry(makeLedgerEntry({
      agent: 'ork:security-auditor',
      stage: 2,
      duration_ms: 5000,
      summary: 'Scanned for vulnerabilities',
      commit_base: ctx2.commitBase,
    }));

    // 5. Read ledger (bufferWrite is sync via global vitest.setup mock — no flush needed)
    const branch = getCurrentBranch();
    const ledger = readBranchLedger(branch);
    expect(ledger.length).toBeGreaterThanOrEqual(2);

    // 7. Format as trailers — no double ork: prefix
    const trailers = formatAsTrailers(ledger);
    expect(trailers).toContain('ork:backend-system-architect');
    expect(trailers).toContain('ork:security-auditor');
    expect(trailers).not.toContain('ork:ork:');

    // 8. Format as PR markdown
    const markdown = formatAsPrMarkdown(ledger);
    expect(markdown).toContain('Agent Team Sheet');
    expect(markdown).toContain('backend-system-architect');
    expect(markdown).toContain('security-auditor');
    expect(markdown).toContain('Agent Credits');

    // 9. Verify deduplication works
    const deduped = deduplicateAgents(ledger);
    const agentNames = deduped.map(e => e.agent);
    const uniqueNames = new Set(agentNames);
    expect(agentNames.length).toBe(uniqueNames.size);

    // 10. Verify threshold filter
    const filtered = filterByThreshold(ledger, 3000);
    for (const e of filtered) {
      expect(e.duration_ms).toBeGreaterThanOrEqual(3000);
    }
  });
});
